#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MAX_ITER 1000
#define LEARNING_RATE 0.01

// Sigmoid function
double sigmoid(double x) {
 return 1 / (1 + exp(-x));
}

int main() {
 int n = 100; // number of samples
 int p = 2; // number of features
 double X[n][p]; // input features
 double y[n]; // target variable
 double weights[p]; // model weights

 // Initialize weights
 for (int i = 0; i < p; i++) {
 weights[i] = 0.0;
 }

 // Train model
 for (int iter = 0; iter < MAX_ITER; iter++) {
 for (int i = 0; i < n; i++) {
 double prediction = sigmoid(X[i][0] * weights[0] + X[i][1] * weights[1]);
 double error = y[i] - prediction;
 weights[0] += LEARNING_RATE * error * X[i][0];
 weights[1] += LEARNING_RATE * error * X[i][1];
 }
 }

 return 0;
}
